// ──────────────────────────────────────────────
// Интерфейсная сегрегация (ISP) — маленькие интерфейсы
// ──────────────────────────────────────────────
// ПЛОХО — "толстый" интерфейс
type BigStorage interface {
    Read(id int) ([]byte, error)
    Write(id int, data []byte) error
    Delete(id int) error
    List() ([]int, error)
    Search(query string) ([]int, error)
    Backup() error
    Restore(path string) error
}

// ХОРОШО — маленькие, компонуемые интерфейсы
type Reader interface {
    Read(ctx context.Context, id int) ([]byte, error)
}
type Writer interface {
    Write(ctx context.Context, id int, data []byte) error
}
type Deleter interface {
    Delete(ctx context.Context, id int) error
}
type Lister interface {
    List(ctx context.Context) ([]int, error)
}

// Compose
type ReadWriter interface {
    Reader
    Writer
}
type Storage interface {
    Reader
    Writer
    Deleter
    Lister
}

// io пакет — эталонный пример из stdlib
// io.Reader    — Read(p []byte) (n int, err error)
// io.Writer    — Write(p []byte) (n int, err error)
// io.Closer    — Close() error
// io.ReadWriter — Reader + Writer
// io.ReadWriteCloser — Reader + Writer + Closer
// io.Seeker    — Seek(offset int64, whence int) (int64, error)

// ──────────────────────────────────────────────
// Interface{} / any — когда нет другого выхода
// ──────────────────────────────────────────────
func processAny(v any) string {
    switch val := v.(type) {
    case nil:          return "nil"
    case int:          return fmt.Sprintf("int: %d", val)
    case float64:      return fmt.Sprintf("float64: %g", val)
    case string:       return fmt.Sprintf("string: %q", val)
    case bool:         return fmt.Sprintf("bool: %v", val)
    case []int:        return fmt.Sprintf("[]int len=%d", len(val))
    case map[string]any: return fmt.Sprintf("map len=%d", len(val))
    case error:        return fmt.Sprintf("error: %v", val)
    case fmt.Stringer: return fmt.Sprintf("stringer: %s", val.String())
    default:           return fmt.Sprintf("unknown: %T = %v", v, v)
    }
}

// ──────────────────────────────────────────────
// Декоратор через интерфейс
// ──────────────────────────────────────────────
type HTTPClient interface {
    Do(req *http.Request) (*http.Response, error)
}

// Декоратор: retry
type RetryClient struct {
    inner    HTTPClient
    maxRetry int
    delay    time.Duration
}

func (c *RetryClient) Do(req *http.Request) (*http.Response, error) {
    var lastErr error
    for i := range c.maxRetry {
        resp, err := c.inner.Do(req)
        if err == nil &amp;&amp; resp.StatusCode &lt; 500 { return resp, nil }
        lastErr = err
        if i &lt; c.maxRetry-1 {
            time.Sleep(c.delay * time.Duration(i+1))  // exponential backoff
        }
    }
    return nil, fmt.Errorf("all %d retries failed: %w", c.maxRetry, lastErr)
}

// Декоратор: logging
type LoggingClient struct {
    inner HTTPClient
    log   *slog.Logger
}

func (c *LoggingClient) Do(req *http.Request) (*http.Response, error) {
    start := time.Now()
    resp, err := c.inner.Do(req)
    c.log.Info("http request",
        "method",   req.Method,
        "url",      req.URL.String(),
        "status",   func() int { if resp != nil { return resp.StatusCode }; return 0 }(),
        "duration", time.Since(start),
        "error",    err,
    )
    return resp, err
}

// Composing decorators
func newHTTPClient(log *slog.Logger) HTTPClient {
    base := &amp;http.Client{Timeout: 15 * time.Second}
    return &amp;LoggingClient{
        inner: &amp;RetryClient{inner: base, maxRetry: 3, delay: 500 * time.Millisecond},
        log:   log,
    }
}

// ──────────────────────────────────────────────
// Embed interface — переопределение части методов
// ──────────────────────────────────────────────
type OverrideWriter struct {
    io.Writer                                 // embed: всё делегируется
    prefix string
}

func (w *OverrideWriter) Write(p []byte) (int, error) {
    return w.Writer.Write(append([]byte(w.prefix), p...))  // переопределить с префиксом
}

// Любой io.Writer + наш префикс
prefixed := &amp;OverrideWriter{Writer: os.Stdout, prefix: "[APP] "}
fmt.Fprintln(prefixed, "hello")               // "[APP] hello"
</code></pre>

Swift 6Kotlin 2.xPython 3.13Go 1.24+ <pre><code>// async/await + Structured Concurrency (Swift 5.5+, строгость Swift 6)

struct User: Codable { let id: Int; let name: String }

// async throws — асинхронная функция, которая может выбросить ошибку
func fetchUser(id: Int) async throws -&gt; User {
    let url = URL(string: "https://jsonplaceholder.typicode.com/users/\(id)")!
    let (data, response) = try await URLSession.shared.data(from: url)
    guard let http = response as? HTTPURLResponse, http.statusCode == 200 else {
        throw URLError(.badServerResponse)
    }
    return try JSONDecoder().decode(User.self, from: data)
}

// Точка входа для async кода
Task {
    do {
        let user = try await fetchUser(id: 1)
        print(user.name)
    } catch {
        print("Error: \(error)")
    }
}

// async let — запускает несколько задач ПАРАЛЛЕЛЬНО
async let user  = fetchUser(id: 1)
async let posts = fetchUser(id: 2)           // оба запроса идут одновременно!
let (u, p) = try await (user, posts)

// TaskGroup — динамическое количество параллельных задач
func fetchAllUsers(ids: [Int]) async throws -&gt; [User] {
    try await withThrowingTaskGroup(of: User.self) { group in
        for id in ids {
            group.addTask { try await fetchUser(id: id) }
        }
        var users: [User] = []
        for try await user in group { users.append(user) }
        return users
    }
}

// Task приоритеты и отмена
let task = Task(priority: .userInitiated) {
    try await fetchUser(id: 1)
}
task.cancel()
// Внутри задачи: try Task.checkCancellation()

// Actor — потокобезопасный изолированный state (Swift 6)
actor BankAccount {
    private var balance: Double = 0

    func deposit(_ amount: Double) { balance += amount }

    func withdraw(_ amount: Double) throws {
        guard balance &gt;= amount else { throw BankError.insufficient }
        balance -= amount
    }

    var currentBalance: Double { balance }
}

let account = BankAccount()
await account.deposit(100)                    // await обязателен для actor

// @MainActor — гарантирует выполнение на главном потоке
@MainActor
class ViewModel: ObservableObject {
    @Published var items: [User] = []
    @Published var isLoading = false

    func load() async {
        isLoading = true
        defer { isLoading = false }
        items = try! await fetchAllUsers(ids: Array(1...5))
    }
}

// AsyncSequence — асинхронная версия Sequence
func streamNumbers() -&gt; AsyncStream&lt;Int&gt; {
    AsyncStream { continuation in
        Task {
            for i in 1...10 {
                try? await Task.sleep(for: .milliseconds(100))
                continuation.yield(i)
            }
            continuation.finish()
        }
    }
}

for await number in streamNumbers() {
    print(number)
}
