import (
    "context"
    "fmt"
    "sync"
    "time"
)

// ──────────────────────────────────────────────
// Goroutines — лёгкие потоки (2–8 KB stack, M:N scheduler)
// ──────────────────────────────────────────────
func goroutineBasics() {
    var wg sync.WaitGroup

    for i := range 5 {
        wg.Add(1)
        go func(n int) {                       // передать n явно — избегать closure capture!
            defer wg.Done()
            fmt.Printf("goroutine %d\n", n)
        }(i)
    }
    wg.Wait()                                  // ждать завершения всех
}

// ──────────────────────────────────────────────
// Channels — коммуникация между горутинами
// ──────────────────────────────────────────────
func channels() {
    // Unbuffered — блокирует отправителя до получения
    ch := make(chan int)
    go func() { ch &lt;- 42 }()
    v := &lt;-ch                                  // 42

    // Buffered — не блокирует до заполнения буфера
    buf := make(chan string, 3)
    buf &lt;- "a"; buf &lt;- "b"; buf &lt;- "c"         // не блокирует
    close(buf)                                 // сигнал — больше данных нет

    for s := range buf {                       // читать до закрытия
        fmt.Println(s)
    }

    // Направленные каналы — документируют намерение
    var sendOnly chan&lt;- int = ch               // только отправка
    var recvOnly &lt;-chan int = ch               // только получение
    _ = sendOnly; _ = recvOnly; _ = v

    // select — мультиплексирование каналов
    ticker := time.NewTicker(500 * time.Millisecond)
    timeout := time.After(2 * time.Second)
    defer ticker.Stop()

    for {
        select {
        case t := &lt;-ticker.C:
            fmt.Println("tick:", t)
        case &lt;-timeout:
            fmt.Println("timeout!")
            return
        }
    }
}

// ──────────────────────────────────────────────
// Context — отмена, таймауты, передача значений
// ──────────────────────────────────────────────
func fetchWithContext(ctx context.Context, url string) ([]byte, error) {
    req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
    if err != nil { return nil, err }

    resp, err := http.DefaultClient.Do(req)
    if err != nil { return nil, fmt.Errorf("fetch %s: %w", url, err) }
    defer resp.Body.Close()
    return io.ReadAll(resp.Body)
}

func contextUsage() {
    // Таймаут
    ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
    defer cancel()                             // ВСЕГДА defer cancel()!

    data, err := fetchWithContext(ctx, "https://api.example.com")
    _ = data; _ = err

    // Дедлайн
    deadline := time.Now().Add(10 * time.Second)
    ctx2, cancel2 := context.WithDeadline(context.Background(), deadline)
    defer cancel2()
    _ = ctx2

    // Отмена
    ctx3, cancel3 := context.WithCancel(context.Background())
    go func() {
        time.Sleep(2 * time.Second)
        cancel3()                              // сигнал отмены
    }()

    select {
    case &lt;-ctx3.Done():
        fmt.Println("cancelled:", ctx3.Err()) // context.Canceled
    }
}

// ──────────────────────────────────────────────
// Паттерн: Worker Pool
// ──────────────────────────────────────────────
func workerPool(ctx context.Context, jobs []int, numWorkers int) []int {
    jobCh    := make(chan int, len(jobs))
    resultCh := make(chan int, len(jobs))

    // Запуск worker'ов
    var wg sync.WaitGroup
    for range numWorkers {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for {
                select {
                case job, ok := &lt;-jobCh:
                    if !ok { return }
                    result := job * job        // тяжёлая работа
                    resultCh &lt;- result
                case &lt;-ctx.Done():
                    return
                }
            }
        }()
    }

    // Отправка задач
    for _, j := range jobs { jobCh &lt;- j }
    close(jobCh)

    // Закрыть resultCh после завершения всех workers
    go func() {
        wg.Wait()
        close(resultCh)
    }()

    // Сбор результатов
    var results []int
    for r := range resultCh {
        results = append(results, r)
    }
    return results
}

// ──────────────────────────────────────────────
// Паттерн: Fan-out / Fan-in
// ──────────────────────────────────────────────
func fanOut[T, R any](
    ctx context.Context,
    items []T,
    workers int,
    process func(context.Context, T) (R, error),
) ([]R, []error) {
    type item struct{ val T }
    type result struct {
        val R
        err error
    }

    jobCh    := make(chan item, len(items))
    resultCh := make(chan result, len(items))

    var wg sync.WaitGroup
    for range workers {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for j := range jobCh {
                v, err := process(ctx, j.val)
                resultCh &lt;- result{v, err}
            }
        }()
    }

    for _, i := range items { jobCh &lt;- item{i} }
    close(jobCh)

    go func() { wg.Wait(); close(resultCh) }()

    var vals []R
    var errs []error
    for r := range resultCh {
        if r.err != nil { errs = append(errs, r.err) } else { vals = append(vals, r.val) }
    }
    return vals, errs
}

