func leaky() &lt;-chan int {
    ch := make(chan int)
    go func() {
        ch &lt;- expensiveOperation()             // блокирует если никто не читает!
    }()
    return ch
}

// ХОРОШО — горутина завершается по context
func notLeaky(ctx context.Context) &lt;-chan int {
    ch := make(chan int, 1)                   // buffered!
    go func() {
        result := expensiveOperation()
        select {
        case ch &lt;- result:
        case &lt;-ctx.Done():                    // выход если отменили
        }
    }()
    return ch
