    "github.com/uptrace/bun/dialect/pgdialect"
    "github.com/uptrace/bun/driver/pgdriver"
)

type Post struct {
    bun.BaseModel `bun:"table:posts,alias:p"`  // таблица и алиас

    ID        int64     `bun:"id,pk,autoincrement"`
    Title     string    `bun:"title,notnull"`
    Body      string    `bun:"body"`
    AuthorID  int64     `bun:"author_id,notnull"`
    Author    *User     `bun:"rel:belongs-to,join:author_id=id"`
    Tags      []string  `bun:",array"`          // PostgreSQL array
    CreatedAt time.Time `bun:"created_at,notnull,default:current_timestamp"`
}

func bunExample() {
    dsn := "postgres://app:secret@localhost/mydb?sslmode=require"
    sqldb := sql.OpenDB(pgdriver.NewConnector(pgdriver.WithDSN(dsn)))
    db := bun.NewDB(sqldb, pgdialect.New())
    defer db.Close()

    ctx := context.Background()

    // Создание таблицы
    _, err := db.NewCreateTable().
        Model((*Post)(nil)).
        IfNotExists().
        Exec(ctx)

    // INSERT
    post := &amp;Post{Title: "Hello Go", Body: "Content...", AuthorID: 1}
    _, err = db.NewInsert().Model(post).Exec(ctx)

    // SELECT с условиями
    var posts []Post
    err = db.NewSelect().
        Model(&amp;posts).
        Relation("Author").                   // загрузить связанного User
        Where("p.author_id = ?", 1).
        Where("? = ANY(p.tags)", "go").
        OrderExpr("p.created_at DESC").
        Limit(10).
        Scan(ctx)

    // UPDATE
    _, err = db.NewUpdate().
        Model(&amp;Post{Title: "Updated"}).
        Column("title").
        Where("id = ?", 1).
        Exec(ctx)

    // DELETE
    _, err = db.NewDelete().
        Model((*Post)(nil)).
        Where("id = ?", 1).
        Exec(ctx)

    // Bulk INSERT
    posts = []Post{
        {Title: "Post 1", AuthorID: 1},
        {Title: "Post 2", AuthorID: 2},
    }
    _, err = db.NewInsert().
        Model(&amp;posts).
        On("CONFLICT (title) DO UPDATE").
        Set("body = EXCLUDED.body").
        Exec(ctx)

    _ = err
}

