func setupLogger() *slog.Logger {
    // JSON handler — для продакшена (парсится Grafana, Loki, Datadog)
    jsonHandler := slog.NewJSONHandler(os.Stdout, &amp;slog.HandlerOptions{
        Level:     slog.LevelDebug,            // минимальный уровень
        AddSource: true,                       // добавить file:line в каждый лог
    })

    // Text handler — для разработки (читаемый)
    textHandler := slog.NewTextHandler(os.Stderr, &amp;slog.HandlerOptions{
        Level: slog.LevelDebug,
    })

    // Выбор по окружению
    var handler slog.Handler
    if os.Getenv("ENV") == "production" {
        handler = jsonHandler
    } else {
        handler = textHandler
    }

    logger := slog.New(handler)
    slog.SetDefault(logger)                    // установить как глобальный
    return logger
}

func loggingPatterns(log *slog.Logger) {
    // Базовые уровни: Debug, Info, Warn, Error
    log.Debug("debug message", "key", "value")
    log.Info("server started", "addr", ":8080", "env", "production")
    log.Warn("slow query", "duration", 500*time.Millisecond, "query", "SELECT ...")
    log.Error("database error", "err", err, "table", "users")

    // Structured attributes
    log.Info("user action",
        slog.String("user_id", "u-123"),
        slog.Int("attempt", 3),
        slog.Bool("success", true),
        slog.Duration("elapsed", 42*time.Millisecond),
        slog.Time("ts", time.Now()),
    )

    // Group — вложенные атрибуты
    log.Info("http request",
        slog.Group("request",
            slog.String("method", "GET"),
            slog.String("path", "/api/users"),
            slog.Int("status", 200),
        ),
        slog.Group("user",
            slog.String("id", "u-123"),
            slog.String("role", "admin"),
        ),
    )

    // With — предустановленные атрибуты (для логгера сервиса)
    serviceLog := log.With(
        slog.String("service", "user-service"),
        slog.String("version", "1.2.3"),
    )
    serviceLog.Info("processing request") // всегда включает service и version

    // Condition check — избежать вычисления дорогих аргументов
    if log.Enabled(context.Background(), slog.LevelDebug) {
