// Sentinel errors — предопределённые ошибки
// ──────────────────────────────────────────────
var (
    ErrNotFound       = errors.New("not found")
    ErrUnauthorized   = errors.New("unauthorized")
    ErrInvalidInput   = errors.New("invalid input")
    ErrInternalServer = errors.New("internal server error")
)

// ──────────────────────────────────────────────
// Оборачивание ошибок (wrapping) — Go 1.13+
// ──────────────────────────────────────────────
func findUser(id int) (*User, error) {
    if id &lt;= 0 {
        return nil, fmt.Errorf("findUser: %w", ErrInvalidInput)  // %w = wrap
    }
    user, err := db.GetUser(id)
    if err != nil {
        // Оборачиваем с контекстом
        return nil, fmt.Errorf("findUser(id=%d): %w", id, err)
    }
    return user, nil
}

// errors.Is — проверка по цепочке
func handleUser(id int) {
    user, err := findUser(id)
    if err != nil {
        switch {
        case errors.Is(err, ErrInvalidInput):
            slog.Warn("bad input", "err", err)
        case errors.Is(err, ErrNotFound):
            slog.Info("user not found", "id", id)
        default:
            slog.Error("unexpected error", "err", err)
        }
        return
    }
    _ = user
}

// errors.As — извлечение типа по цепочке
func process(id int) {
    _, err := findUser(id)
    var valErr *ValidationError
    var notFound *NotFoundError
    switch {
    case errors.As(err, &amp;valErr):
        fmt.Printf("Validation failed on field: %s\n", valErr.Field)
    case errors.As(err, &amp;notFound):
        fmt.Printf("Resource %s not found\n", notFound.Resource)
    }
}

// ──────────────────────────────────────────────
// errors.Join (Go 1.20+) — объединить несколько ошибок
// ──────────────────────────────────────────────
func validateUser(u User) error {
    var errs []error
    if u.name == "" {
        errs = append(errs, &amp;ValidationError{Field: "name", Message: "required"})
    }
    if u.email == "" {
        errs = append(errs, &amp;ValidationError{Field: "email", Message: "required"})
    }
    return errors.Join(errs...)                // nil если errs пустой
}

// ──────────────────────────────────────────────
// Паника и recover (только для критических ошибок!)
// ──────────────────────────────────────────────
func safeDivide(a, b int) (result int, err error) {
    defer func() {
        if r := recover(); r != nil {
            err = fmt.Errorf("recovered from panic: %v", r)
        }
    }()
    return a / b, nil                          // panic при b==0
}

// Идиоматический паттерн: Must для инициализации
func Must[T any](v T, err error) T {
    if err != nil { panic(err) }
    return v
}

// Использование только при инициализации!
re := Must(regexp.Compile(`^\d+$`))           // panic если невалидный regex

