func Map[T, R any](s []T, fn func(T) R) []R {
    result := make([]R, len(s))
    for i, v := range s { result[i] = fn(v) }
    return result
}

func Filter[T any](s []T, fn func(T) bool) []T {
    result := make([]T, 0, len(s)/2)
    for _, v := range s {
        if fn(v) { result = append(result, v) }
    }
    return result
}

func Reduce[T, R any](s []T, init R, fn func(R, T) R) R {
    acc := init
    for _, v := range s { acc = fn(acc, v) }
    return acc
}

// FlatMap
func FlatMap[T, R any](s []T, fn func(T) []R) []R {
    var result []R
    for _, v := range s { result = append(result, fn(v)...) }
    return result
}

