func Curry[A, B, C any](fn func(A, B) C) func(A) func(B) C {
    return func(a A) func(B) C {
        return func(b B) C { return fn(a, b) }
    }
}

func Partial[A, B, C any](fn func(A, B) C, a A) func(B) C {
    return func(b B) C { return fn(a, b) }
}

