byAge := GroupBy(people, func(p Person) int { return p.Age })
// map[25:[{Bob 25}] 30:[{Alice 30} {Charlie 30}]]

chunks := Chunk([]int{1,2,3,4,5,6,7}, 3)
// [[1 2 3] [4 5 6] ][6]
