// sync/atomic — lock-free operations
// ──────────────────────────────────────────────
type AtomicCounter struct {
    count int64                               // MUST be 64-bit aligned!
}

func (c *AtomicCounter) Add(delta int64) int64 {
    return atomic.AddInt64(&amp;c.count, delta)
}
func (c *AtomicCounter) Load() int64 {
    return atomic.LoadInt64(&amp;c.count)
}
func (c *AtomicCounter) Store(val int64) {
    atomic.StoreInt64(&amp;c.count, val)
}
func (c *AtomicCounter) CompareAndSwap(old, new int64) bool {
    return atomic.CompareAndSwapInt64(&amp;c.count, old, new)
}
func (c *AtomicCounter) Swap(new int64) int64 {
    return atomic.SwapInt64(&amp;c.count, new)
}

