}

// ──────────────────────────────────────────────
// Common mistake: goroutine leak
// ──────────────────────────────────────────────
// BAD — the goroutine hangs forever if nobody reads from ch
func leaky() &lt;-chan int {
    ch := make(chan int)
    go func() {
        ch &lt;- expensiveOperation()             // blocks if nobody reads!
    }()
    return ch
}

// GOOD — the goroutine exits via context
func notLeaky(ctx context.Context) &lt;-chan int {
    ch := make(chan int, 1)                   // buffered!
    go func() {
        result := expensiveOperation()
        select {
        case ch &lt;- result:
        case &lt;-ctx.Done():                    // exit if cancelled
        }
    }()
    return ch
}
