    inner UserService
    cache *Cache[int, *User]
}

func (s *CachingService) GetUser(ctx context.Context, id int) (*User, error) {
    if user, ok := s.cache.Get(id); ok { return user, nil }
    user, err := s.inner.GetUser(ctx, id)
    if err == nil { s.cache.Set(id, user) }
    return user, err
}

