    a.logger.Info("starting", "addr", a.server.Addr)
    go func() {
        &lt;-ctx.Done()
        a.server.Shutdown(context.Background())
    }()
    if err := a.server.ListenAndServe(); !errors.Is(err, http.ErrServerClosed) {
        return err
    }
    return nil
