func newRootCmd() *cobra.Command {
    var (
        cfgFile string
        verbose bool
    )

    root := &amp;cobra.Command{
        Use:   "myapp",
        Short: "My application",
        Long:  `A comprehensive CLI application built with Go and Cobra.`,
        PersistentPreRun: func(cmd *cobra.Command, args []string) {
            if verbose {
                slog.SetLogLoggerLevel(slog.LevelDebug)
            }
        },
    }

    // Persistent flags — available in all subcommands
    root.PersistentFlags().StringVar(&amp;cfgFile, "config", "", "config file path")
    root.PersistentFlags().BoolVarP(&amp;verbose, "verbose", "v", false, "verbose output")

    // Subcommands
    root.AddCommand(newServeCmd())
    root.AddCommand(newMigrateCmd())
    root.AddCommand(newUserCmd())

    return root
}

func newServeCmd() *cobra.Command {
    var port int

    cmd := &amp;cobra.Command{
        Use:   "serve",
        Short: "Start the HTTP server",
        RunE: func(cmd *cobra.Command, args []string) error {
            return runServer(port)             // RunE instead of Run — returns error
        },
    }
    cmd.Flags().IntVarP(&amp;port, "port", "p", 8080, "HTTP port")
    cmd.MarkFlagRequired("port")              // required flag
    return cmd
}

func newMigrateCmd() *cobra.Command {
    cmd := &amp;cobra.Command{
        Use:   "migrate",
        Short: "Database migration commands",
    }
    cmd.AddCommand(&amp;cobra.Command{
        Use:   "up",
        Short: "Apply all pending migrations",
        RunE:  func(cmd *cobra.Command, args []string) error { return runMigrateUp() },
    })
    cmd.AddCommand(&amp;cobra.Command{
        Use:   "down",
        Short: "Rollback last migration",
        RunE:  func(cmd *cobra.Command, args []string) error { return runMigrateDown() },
    })
    return cmd
}

