    user, err := findUser(id)
    if err != nil {
        switch {
        case errors.Is(err, ErrInvalidInput):
            slog.Warn("bad input", "err", err)
        case errors.Is(err, ErrNotFound):
            slog.Info("user not found", "id", id)
        default:
            slog.Error("unexpected error", "err", err)
        }
        return
    }
