    _, err := findUser(id)
    var valErr *ValidationError
    var notFound *NotFoundError
    switch {
    case errors.As(err, &amp;valErr):
        fmt.Printf("Validation failed on field: %s\n", valErr.Field)
    case errors.As(err, &amp;notFound):
