// ──────────────────────────────────────────────
// Basic operations — os package
// ──────────────────────────────────────────────
func fileBasics() error {
    // ─── Write file ─────────────────────────
    // os.WriteFile — atomic write (via temp file on most file systems)
    data := []byte("Hello, Go!\n")
    if err := os.WriteFile("output.txt", data, 0644); err != nil {
        return fmt.Errorf("write file: %w", err)
    }

    // Write via os.Create + bufio.Writer (efficient for large files)
    f, err := os.Create("large.txt")
    if err != nil { return err }
    defer f.Close()

    bw := bufio.NewWriterSize(f, 64*1024)      // 64 KB buffer
    for i := range 100_000 {
        fmt.Fprintf(bw, "line %d\n", i)
    }
    if err := bw.Flush(); err != nil { return err } // flush the buffer!

    // ─── Read file ──────────────────────────
    content, err := os.ReadFile("output.txt") // entire file into memory
    if err != nil { return err }
    fmt.Println(string(content))

    // Byte-by-byte / line-by-line reading (large files)
    f2, err := os.Open("large.txt")
    if err != nil { return err }
    defer f2.Close()

    scanner := bufio.NewScanner(f2)
    scanner.Buffer(make([]byte, 1&lt;&lt;20), 1&lt;&lt;20) // 1 MB buffer for long lines
    lineCount := 0
    for scanner.Scan() {
        line := scanner.Text()
        _ = line
        lineCount++
    }
    if err := scanner.Err(); err != nil { return err }
    fmt.Println("lines:", lineCount)

    // ─── Append to the end of the file ──────
    f3, err := os.OpenFile("log.txt",
        os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
    if err != nil { return err }
    defer f3.Close()
    fmt.Fprintln(f3, time.Now().Format(time.RFC3339), "app started")

    // ─── Existence check / stat ─────────────
    info, err := os.Stat("output.txt")
    if err != nil {
        if errors.Is(err, os.ErrNotExist) {
            fmt.Println("file not found")
        }
        return err
    }
    fmt.Printf("size=%d mode=%s modtime=%s\n",
        info.Size(), info.Mode(), info.ModTime())

    // ─── Rename and delete ──────────────────
    os.Rename("output.txt", "output_new.txt")
    os.Remove("output_new.txt")
    os.RemoveAll("temp_dir")               // recursively

    return nil
}

// ──────────────────────────────────────────────
// Working with directories
// ──────────────────────────────────────────────
func dirOperations() error {
    // Create directories
    os.MkdirAll("data/cache/tmp", 0755)    // like mkdir -p

    // List a directory
    entries, err := os.ReadDir(".")
    if err != nil { return err }
    for _, e := range entries {
        info, _ := e.Info()
        fmt.Printf("%-30s %8d %s\n", e.Name(), info.Size(), info.Mode())
    }

    // Recursive walk — filepath.WalkDir (Go 1.16+, more efficient than Walk)
    err = filepath.WalkDir(".", func(path string, d fs.DirEntry, err error) error {
        if err != nil { return err }

        if d.IsDir() &amp;&amp; d.Name() == ".git" {
            return filepath.SkipDir  // skip subtree
        }

        if !d.IsDir() &amp;&amp; strings.HasSuffix(path, ".go") {
            info, _ := d.Info()
            fmt.Printf("%s (%d bytes)\n", path, info.Size())
        }
        return nil
    })

    // Temp files — name is automatically safe
    tmpFile, err := os.CreateTemp("", "app-*.tmp")  // * is replaced by a random string
    if err != nil { return err }
    defer os.Remove(tmpFile.Name())                  // remove on exit
    defer tmpFile.Close()
    tmpFile.WriteString("temp data")

    // Temp directory
    tmpDir, err := os.MkdirTemp("", "app-*")
    if err != nil { return err }
    defer os.RemoveAll(tmpDir)

    _ = err
    return nil
}

// ──────────────────────────────────────────────
// Atomic file write — via rename
// (protects against data loss if the process crashes mid-write)
// ──────────────────────────────────────────────
func writeFileAtomic(path string, data []byte, perm os.FileMode) error {
    dir := filepath.Dir(path)

    // Create a temp file on the same file system (important for atomic rename!)
    tmp, err := os.CreateTemp(dir, ".tmp-*")
    if err != nil { return fmt.Errorf("create temp: %w", err) }
    tmpName := tmp.Name()

    defer func() {
        tmp.Close()
        os.Remove(tmpName)                   // cleanup if something goes wrong
    }()

    if _, err := tmp.Write(data); err != nil {
        return fmt.Errorf("write temp: %w", err)
    }
    if err := tmp.Sync(); err != nil {       // fsync — flush to disk!
        return fmt.Errorf("sync: %w", err)
    }
    tmp.Close()

    if err := os.Chmod(tmpName, perm); err != nil { return err }

    // Atomic rename: either old or new — never partial
    return os.Rename(tmpName, path)
}

// ──────────────────────────────────────────────
// CSV — encoding/csv (built in)
// ──────────────────────────────────────────────
type Record struct {
    Name  string
    Email string
    Age   int
}

func writeCSV(path string, records []Record) error {
    f, err := os.Create(path)
    if err != nil { return err }
    defer f.Close()

    w := csv.NewWriter(f)
    defer w.Flush()                          // MUST call Flush!

    // Header
    if err := w.Write([]string{"name", "email", "age"}); err != nil {
        return err
    }

    for _, r := range records {
        if err := w.Write([]string{
            r.Name, r.Email, strconv.Itoa(r.Age),
        }); err != nil { return err }
    }
    return w.Error()
}

func readCSV(path string) ([]Record, error) {
    f, err := os.Open(path)
    if err != nil { return nil, err }
    defer f.Close()

    r := csv.NewReader(f)
    r.TrimLeadingSpace = true
    r.Comment = '#'                          // ignore lines starting with #

    // Skip header
    if _, err := r.Read(); err != nil { return nil, err }

    var records []Record
    for {
        row, err := r.Read()
        if err == io.EOF { break }
        if err != nil { return nil, err }

        age, _ := strconv.Atoi(row[2])
        records = append(records, Record{
            Name:  row[0],
            Email: row[1],
            Age:   age,
        })
    }
    return records, nil
}

