// ──────────────────────────────────────────────
// Memoization through a generic closure
// ──────────────────────────────────────────────
func Memoize[K comparable, V any](fn func(K) V) func(K) V {
    cache := make(map[K]V)
    var mu sync.RWMutex
    return func(k K) V {
        mu.RLock()
        if v, ok := cache[k]; ok { mu.RUnlock(); return v }
        mu.RUnlock()
        mu.Lock()
        defer mu.Unlock()
        if v, ok := cache[k]; ok { return v }  // double-check
        v := fn(k)
        cache[k] = v
        return v
    }
}

var fib func(int) int
