// Either / Result through generics
// ──────────────────────────────────────────────
type Either[L, R any] struct {
    left  L
    right R
    isRight bool
}

func Left[L, R any](v L) Either[L, R]  { return Either[L, R]{left: v} }
func Right[L, R any](v R) Either[L, R] { return Either[L, R]{right: v, isRight: true} }

func (e Either[L, R]) Map(fn func(R) R) Either[L, R] {
    if !e.isRight { return e }
    return Right[L, R](fn(e.right))
}

func (e Either[L, R]) FlatMap(fn func(R) Either[L, R]) Either[L, R] {
    if !e.isRight { return e }
    return fn(e.right)
}
