            draw(in: CGRect(origin: .zero, size: newSize))
        }
    }

    /// Crop to a rectangle
    func cropped(to rect: CGRect) -&gt; UIImage? {
        let scale = self.scale
        let scaledRect = CGRect(
            x: rect.origin.x * scale,    y: rect.origin.y * scale,
            width: rect.width * scale,   height: rect.height * scale
        )
        guard let cgImage = cgImage?.cropping(to: scaledRect) else { return nil }
        return UIImage(cgImage: cgImage, scale: scale, orientation: imageOrientation)
    }

    /// Thumbnail via Image I/O (fast, no full decode)
    static func thumbnail(from url: URL, maxPixelSize: Int) -&gt; UIImage? {
        let options: [CFString: Any] = [
            kCGImageSourceShouldCache: false,
            kCGImageSourceCreateThumbnailFromImageAlways: true,
            kCGImageSourceThumbnailMaxPixelSize: maxPixelSize,
        ]
        guard let source = CGImageSourceCreateWithURL(url as CFURL, nil),
              let cgImage = CGImageSourceCreateThumbnailAtIndex(source, 0, options as CFDictionary)
        else { return nil }
        return UIImage(cgImage: cgImage)
    }
