        IdleConnTimeout:     90 * time.Second,
    },
}

// BAD: http.Get without timeout — may hang forever!
// resp, _ := http.Get("https://api.example.com")

// GOOD — client with timeout and context
func apiGet[T any](ctx context.Context, url string) (T, error) {
    var result T
    req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
    if err != nil { return result, fmt.Errorf("build request: %w", err) }

    resp, err := httpClient.Do(req)
    if err != nil { return result, fmt.Errorf("do request: %w", err) }
    defer resp.Body.Close()

    if resp.StatusCode != http.StatusOK {
        body, _ := io.ReadAll(resp.Body)
        return result, fmt.Errorf("status %d: %s", resp.StatusCode, body)
    }

    if err := json.NewDecoder(resp.Body).Decode(&amp;result); err != nil {
        return result, fmt.Errorf("decode response: %w", err)
    }
    return result, nil
}

// POST with JSON body
func apiPost[T any](ctx context.Context, url string, body any) (T, error) {
    var result T
    b, err := json.Marshal(body)
    if err != nil { return result, err }

    req, err := http.NewRequestWithContext(ctx, http.MethodPost, url,
        bytes.NewReader(b))
    if err != nil { return result, err }
    req.Header.Set("Content-Type", "application/json")
    req.Header.Set("Accept",       "application/json")

    resp, err := httpClient.Do(req)
    if err != nil { return result, err }
    defer resp.Body.Close()

    if err := json.NewDecoder(resp.Body).Decode(&amp;result); err != nil {
        return result, err
    }
    return result, nil
}

