// HTTP Server — net/http (built in, production-ready in 2026)
// ──────────────────────────────────────────────
type Handler struct {
    userRepo UserRepository
    logger   *slog.Logger
}

// Middleware
func loggingMiddleware(log *slog.Logger, next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        start := time.Now()
        next.ServeHTTP(w, r)
        log.Info("request",
            "method",   r.Method,
            "path",     r.URL.Path,
            "duration", time.Since(start),
        )
    })
}

func authMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        token := r.Header.Get("Authorization")
        if token == "" {
            http.Error(w, "unauthorized", http.StatusUnauthorized)
            return
        }
        next.ServeHTTP(w, r)
    })
}

// Helper functions
func respondJSON(w http.ResponseWriter, status int, v any) {
    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(status)
    json.NewEncoder(w).Encode(v)
}

func respondError(w http.ResponseWriter, status int, msg string) {
    respondJSON(w, status, map[string]string{"error": msg})
}

// Handlers
func (h *Handler) getUser(w http.ResponseWriter, r *http.Request) {
    id := r.PathValue("id")                   // Go 1.22+ routing patterns!
    user, err := h.userRepo.FindByID(r.Context(), id)
    if err != nil {
        if errors.Is(err, ErrNotFound) {
            respondError(w, http.StatusNotFound, "user not found")
        } else {
            respondError(w, http.StatusInternalServerError, "internal error")
        }
        return
    }
    respondJSON(w, http.StatusOK, user)
}

func (h *Handler) createUser(w http.ResponseWriter, r *http.Request) {
    var req struct {
        Name  string `json:"name"`
        Email string `json:"email"`
    }
    if err := json.NewDecoder(r.Body).Decode(&amp;req); err != nil {
        respondError(w, http.StatusBadRequest, "invalid JSON")
        return
    }

    user, err := h.userRepo.Create(r.Context(), req.Name, req.Email)
    if err != nil {
        respondError(w, http.StatusInternalServerError, err.Error())
        return
    }
    respondJSON(w, http.StatusCreated, user)
}

// Router — Go 1.22+ enhanced ServeMux (patterns with methods!)
func NewRouter(h *Handler, log *slog.Logger) http.Handler {
    mux := http.NewServeMux()

    // Go 1.22+ syntax: METHOD /path/{param}
    mux.HandleFunc("GET /api/users/{id}", h.getUser)
    mux.HandleFunc("POST /api/users",     h.createUser)
    mux.HandleFunc("DELETE /api/users/{id}", h.deleteUser)
    mux.HandleFunc("GET /health", func(w http.ResponseWriter, r *http.Request) {
        respondJSON(w, http.StatusOK, map[string]string{"status": "ok"})
    })

    // Apply middleware (chain)
    return loggingMiddleware(log, mux)
}

func main() {
    log := slog.Default()
    h := &amp;Handler{userRepo: newUserRepo(), logger: log}

    srv := &amp;http.Server{
        Addr:         ":8080",
        Handler:      NewRouter(h, log),
        ReadTimeout:  10 * time.Second,
        WriteTimeout: 10 * time.Second,
        IdleTimeout:  60 * time.Second,
    }

    log.Info("starting server", "addr", srv.Addr)
    if err := srv.ListenAndServe(); err != nil {
        log.Error("server failed", "err", err)
    }
}

