// WebSocket — golang.org/x/net/websocket or nhooyr.io/websocket
// ──────────────────────────────────────────────
// go get nhooyr.io/websocket
import "nhooyr.io/websocket"
import "nhooyr.io/websocket/wsjson"

func wsHandler(w http.ResponseWriter, r *http.Request) {
    conn, err := websocket.Accept(w, r, &amp;websocket.AcceptOptions{
        InsecureSkipVerify: false,
    })
    if err != nil { return }
    defer conn.CloseNow()

    ctx := conn.CloseRead(r.Context())

    for {
        var msg map[string]any
        if err := wsjson.Read(ctx, conn, &amp;msg); err != nil { break }
        if err := wsjson.Write(ctx, conn, msg); err != nil { break } // echo
    }
}
