func operators() {
    // Arithmetic
    a, b := 10, 3
    _ = a + b     // 13
    _ = a - b     // 7
    _ = a * b     // 30
    _ = a / b     // 3 (integer division!)
    _ = a % b     // 1
    _ = -a        // -10

    // Comparison (bool result)
    _ = a == b    // false
    _ = a != b    // true
    _ = a &lt; b     // false
    _ = a &lt;= b    // false
    _ = a &gt; b     // true
    _ = a &gt;= b    // true

    // Logical
    x, y := true, false
    _ = x &amp;&amp; y    // false (short-circuit: y is not evaluated if x=false)
    _ = x || y    // true  (short-circuit: y is not evaluated if x=true)
    _ = !x        // false

    // Bitwise
    n := 0b1010
    _ = n &amp; 0b1100  // AND: 0b1000
    _ = n | 0b0101  // OR:  0b1111
    _ = n ^ 0b1100  // XOR: 0b0110
    _ = n &lt;&lt; 2      // left shift: 0b101000
    _ = n &gt;&gt; 1      // right shift: 0b0101
    _ = ^n          // NOT: invert all bits
    _ = n &amp;^ 0b1100 // AND NOT (bit clear): 0b0010

    // Assignment
    c := 5
    c += 3          // c = 8
    c -= 1          // c = 7
    c *= 2          // c = 14
    c /= 2          // c = 7
    c %= 3          // c = 1
    c &lt;&lt;= 1         // c = 2
    c &gt;&gt;= 1         // c = 1
    c &amp;= 0xFF
    c |= 0b0001
    c ^= 0b0011

    // Increment / decrement — statement ONLY (not expression!)
    i := 0
    i++             // i = 1  (no ++i, no x = i++)
    i--             // i = 0

    _ = a; _ = b; _ = x; _ = y; _ = n; _ = c; _ = i
}

