func regexBasics() {
    // ─── Basic methods ───────────────────────
    re := regexp.MustCompile(`\d+`)

    re.MatchString("hello 42")           // true — has a match
    re.FindString("hello 42 world 7")    // "42" — first match
    re.FindAllString("42 7 100", -1)     // ["42", "7", "100"] — all (-1 = unlimited)
    re.FindAllString("42 7 100", 2)      // ["42", "7"] — first 2
    re.FindStringIndex("hello 42")       // [6, 8] — position of first match
    re.ReplaceAllString("a1b2c3", "X")  // "XbXcX"
    re.Split("a1b2c3", -1)              // ["a","b","c",""] — split by matches

