    text := "2026-03-20"
    match := dateRe.FindStringSubmatch(text)
    // ["2026-03-20", "2026", "03", "20"]

    // Access by group name
    names := dateRe.SubexpNames()        // ["", "year", "month", "day"]
    result := make(map[string]string)
    for i, name := range names {
        if i &gt; 0 &amp;&amp; name != "" &amp;&amp; i &lt; len(match) {
            result[name] = match[i]
        }
    }
    fmt.Printf("year=%s, month=%s, day=%s\n",
        result["year"], result["month"], result["day"])

    // Convenient wrapper for named groups
    groups := namedGroups(dateRe, text)
    // groups["year"] = "2026"

    // ─── Log parsing ────────────────────────
    logLine := `127.0.0.1 - frank [18/Mar/2026] "GET /api HTTP/1.1" 200 1234`
    logGroups := namedGroups(logRe, logLine)
    fmt.Printf("IP: %s, Method: %s, Status: %s\n",
        logGroups["ip"], logGroups["method"], logGroups["status"])

    // All matches
    logs := `127.0.0.1 - alice [01/Mar] "GET /a HTTP/1.1" 200 100
10.0.0.1 - bob [02/Mar] "POST /b HTTP/1.1" 404 50`

    logRe.FindAllStringSubmatch(logs, -1)  // all log lines

    // ─── Replacement with function ───────────
    priceRe := regexp.MustCompile(`\d+\.\d{2}`)
    prices := "Total: 12.50 + 3.99 = 16.49"
    doubled := priceRe.ReplaceAllStringFunc(prices, func(s string) string {
        var f float64
        fmt.Sscanf(s, "%f", &amp;f)
        return fmt.Sprintf("%.2f", f*2)
    })
    // "Total: 25.00 + 7.98 = 32.98"

    // camelCase → snake_case
    camelRe := regexp.MustCompile(`([A-Z])`)
    toSnake := func(s string) string {
        result := camelRe.ReplaceAllStringFunc(s, func(m string) string {
            return "_" + strings.ToLower(m)
        })
        return strings.TrimPrefix(result, "_")
    }
    toSnake("camelCaseString")               // "camel_case_string"

    // ─── Validation ────────────────────────────
    emailRe.MatchString("alice@example.com")  // true
    emailRe.MatchString("not-an-email")       // false
    phoneRe.MatchString("+49 30 12345678")    // true

    fmt.Println(doubled, groups)
}

// ─── Helper function for named groups ─────────
func namedGroups(re *regexp.Regexp, s string) map[string]string {
    match := re.FindStringSubmatch(s)
    result := make(map[string]string, len(match))
    for i, name := range re.SubexpNames() {
        if i &gt; 0 &amp;&amp; name != "" &amp;&amp; i &lt; len(match) {
            result[name] = match[i]
        }
    }
    return result
}

// ─── Iterator over all matches with named groups ─
func allMatches(re *regexp.Regexp, s string) []map[string]string {
    all := re.FindAllStringSubmatch(s, -1)
    names := re.SubexpNames()
    result := make([]map[string]string, 0, len(all))
    for _, match := range all {
        groups := make(map[string]string)
        for i, name := range names {
            if i &gt; 0 &amp;&amp; name != "" {
                groups[name] = match[i]
            }
        }
        result = append(result, groups)
    }
    return result
}
