// ──────────────────────────────────────────────
const bcryptCost = 12              // OWASP: minimum 10, recommended 12-14

func hashPasswordBcrypt(password string) (string, error) {
    bytes, err := bcrypt.GenerateFromPassword([]byte(password), bcryptCost)
    return string(bytes), err
}

func verifyPasswordBcrypt(password, hash string) bool {
    err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(password))
    return err == nil
}

// Argon2id — modern standard (winner of PHC 2015)
type Argon2Params struct {
    Memory      uint32 // KB
    Iterations  uint32
    Parallelism uint8
    SaltLen     uint32
    KeyLen      uint32
}

// OWASP 2026: memory=64MB, iterations=3
var DefaultArgon2Params = Argon2Params{
    Memory:      64 * 1024, // 64 MB
    Iterations:  3,
    Parallelism: 4,
    SaltLen:     16,
    KeyLen:      32,
}

func hashPasswordArgon2(password string, p Argon2Params) (string, error) {
    salt := make([]byte, p.SaltLen)
    if _, err := io.ReadFull(rand.Reader, salt); err != nil {
        return "", fmt.Errorf("generate salt: %w", err)
    }

    hash := argon2.IDKey([]byte(password), salt,
        p.Iterations, p.Memory, p.Parallelism, p.KeyLen)

    // Format: $argon2id$v=19$m=65536,t=3,p=4$&lt;salt&gt;$&lt;hash&gt;
    encoded := fmt.Sprintf("$argon2id$v=%d$m=%d,t=%d,p=%d$%s$%s",
        argon2.Version,
        p.Memory, p.Iterations, p.Parallelism,
        base64.RawStdEncoding.EncodeToString(salt),
        base64.RawStdEncoding.EncodeToString(hash),
    )
    return encoded, nil
}

func verifyPasswordArgon2(password, encodedHash string) (bool, error) {
    var version int
    var p Argon2Params
    var saltB64, hashB64 string

    _, err := fmt.Sscanf(encodedHash,
        "$argon2id$v=%d$m=%d,t=%d,p=%d$%s$%s",
        &amp;version, &amp;p.Memory, &amp;p.Iterations, &amp;p.Parallelism, &amp;saltB64, &amp;hashB64)
    if err != nil { return false, fmt.Errorf("decode hash: %w", err) }

    salt, _ := base64.RawStdEncoding.DecodeString(saltB64)
    expectedHash, _ := base64.RawStdEncoding.DecodeString(hashB64)
    p.KeyLen = uint32(len(expectedHash))

    actualHash := argon2.IDKey([]byte(password), salt,
        p.Iterations, p.Memory, p.Parallelism, p.KeyLen)

    // subtle.ConstantTimeCompare — protection against timing attacks
    return subtle.ConstantTimeCompare(actualHash, expectedHash) == 1, nil
}

// ──────────────────────────────────────────────
// ② Hashes: SHA-256, SHA-512
// ──────────────────────────────────────────────
func hashData() {
    data := []byte("sensitive data")

    // SHA-256
    h256 := sha256.Sum256(data)               // [32]byte
    fmt.Println(hex.EncodeToString(h256[:]))

    // SHA-512
    import "crypto/sha512"
    h512 := sha512.Sum512(data)               // [64]byte

    // HMAC-SHA256 — for message verification
    import "crypto/hmac"
    key  := []byte(os.Getenv("HMAC_SECRET"))
    mac  := hmac.New(sha256.New, key)
    mac.Write(data)
    sig  := mac.Sum(nil)

    // Verify HMAC — constant-time
    expected := computeHMAC(data, key)
    if !hmac.Equal(sig, expected) {
        fmt.Println("signature mismatch!")
    }
    _ = h512
}

func computeHMAC(data, key []byte) []byte {
    import "crypto/hmac"
    mac := hmac.New(sha256.New, key)
    mac.Write(data)
    return mac.Sum(nil)
}

