rs256_token = jwt.encode(
    {"sub": "user-123", "exp": datetime.now(UTC) + timedelta(hours=1)},
    private_key, algorithm="RS256"
)
claims = jwt.decode(rs256_token, public_key, algorithms=["RS256"])

