// ──────────────────────────────────────────────
// Interface Segregation Principle (ISP) — kleine Interfaces
// ──────────────────────────────────────────────
// SCHLECHT — "fettes" Interface
type BigStorage interface {
    Read(id int) ([]byte, error)
    Write(id int, data []byte) error
    Delete(id int) error
    List() ([]int, error)
    Search(query string) ([]int, error)
    Backup() error
    Restore(path string) error
}

// GUT — kleine, kombinierbare Interfaces
type Reader interface {
    Read(ctx context.Context, id int) ([]byte, error)
}
type Writer interface {
    Write(ctx context.Context, id int, data []byte) error
}
type Deleter interface {
    Delete(ctx context.Context, id int) error
}
type Lister interface {
    List(ctx context.Context) ([]int, error)
}

// Komposition
type ReadWriter interface {
    Reader
    Writer
}
type Storage interface {
    Reader
    Writer
    Deleter
    Lister
}

// io-Paket — kanonisches Beispiel aus der stdlib
// io.Reader    — Read(p []byte) (n int, err error)
// io.Writer    — Write(p []byte) (n int, err error)
// io.Closer    — Close() error
// io.ReadWriter — Reader + Writer
// io.ReadWriteCloser — Reader + Writer + Closer
// io.Seeker    — Seek(offset int64, whence int) (int64, error)

// ──────────────────────────────────────────────
// Interface{} / any — wenn es keinen anderen Ausweg gibt
// ──────────────────────────────────────────────
func processAny(v any) string {
    switch val := v.(type) {
    case nil:          return "nil"
    case int:          return fmt.Sprintf("int: %d", val)
    case float64:      return fmt.Sprintf("float64: %g", val)
    case string:       return fmt.Sprintf("string: %q", val)
    case bool:         return fmt.Sprintf("bool: %v", val)
    case []int:        return fmt.Sprintf("[]int len=%d", len(val))
    case map[string]any: return fmt.Sprintf("map len=%d", len(val))
    case error:        return fmt.Sprintf("error: %v", val)
    case fmt.Stringer: return fmt.Sprintf("stringer: %s", val.String())
    default:           return fmt.Sprintf("unknown: %T = %v", v, v)
    }
}

// ──────────────────────────────────────────────
// Dekorator über Interface
// ──────────────────────────────────────────────
type HTTPClient interface {
    Do(req *http.Request) (*http.Response, error)
}

// Dekorator: retry
type RetryClient struct {
    inner    HTTPClient
    maxRetry int
    delay    time.Duration
}

func (c *RetryClient) Do(req *http.Request) (*http.Response, error) {
    var lastErr error
    for i := range c.maxRetry {
        resp, err := c.inner.Do(req)
        if err == nil &amp;&amp; resp.StatusCode &lt; 500 { return resp, nil }
        lastErr = err
        if i &lt; c.maxRetry-1 {
            time.Sleep(c.delay * time.Duration(i+1))  // Exponential Backoff
        }
    }
    return nil, fmt.Errorf("all %d retries failed: %w", c.maxRetry, lastErr)
}

// Dekorator: Logging
type LoggingClient struct {
    inner HTTPClient
    log   *slog.Logger
}

func (c *LoggingClient) Do(req *http.Request) (*http.Response, error) {
    start := time.Now()
    resp, err := c.inner.Do(req)
    c.log.Info("http request",
        "method",   req.Method,
        "url",      req.URL.String(),
        "status",   func() int { if resp != nil { return resp.StatusCode }; return 0 }(),
        "duration", time.Since(start),
        "error",    err,
    )
    return resp, err
}

// Dekoratoren komponieren
func newHTTPClient(log *slog.Logger) HTTPClient {
    base := &amp;http.Client{Timeout: 15 * time.Second}
    return &amp;LoggingClient{
        inner: &amp;RetryClient{inner: base, maxRetry: 3, delay: 500 * time.Millisecond},
        log:   log,
    }
}

// ──────────────────────────────────────────────
// Embed Interface — Teil der Methoden überschreiben
// ──────────────────────────────────────────────
type OverrideWriter struct {
    io.Writer                                 // embed: alles wird delegiert
    prefix string
}

func (w *OverrideWriter) Write(p []byte) (int, error) {
    return w.Writer.Write(append([]byte(w.prefix), p...))  // mit Präfix überschreiben
}

// Beliebiger io.Writer + unser Präfix
prefixed := &amp;OverrideWriter{Writer: os.Stdout, prefix: "[APP] "}
fmt.Fprintln(prefixed, "hello")               // "[APP] hello"
