// ──────────────────────────────────────────────
// Goroutines — leichtgewichtige Threads (2–8 KB Stack, M:N-Scheduler)
// ──────────────────────────────────────────────
func goroutineBasics() {
    var wg sync.WaitGroup

    for i := range 5 {
        wg.Add(1)
        go func(n int) {                       // n explizit übergeben — Closure-Capture vermeiden!
            defer wg.Done()
            fmt.Printf("goroutine %d\n", n)
        }(i)
    }
    wg.Wait()                                  // auf Abschluss aller warten
}

// ──────────────────────────────────────────────
// Channels — Kommunikation zwischen Goroutines
// ──────────────────────────────────────────────
func channels() {
    // Unbuffered — blockiert den Sender bis zum Empfang
    ch := make(chan int)
    go func() { ch &lt;- 42 }()
    v := &lt;-ch                                  // 42

    // Buffered — blockiert nicht, bis der Puffer voll ist
    buf := make(chan string, 3)
    buf &lt;- "a"; buf &lt;- "b"; buf &lt;- "c"         // blockiert nicht
    close(buf)                                 // Signal — keine weiteren Daten

    for s := range buf {                       // bis zum Schließen lesen
        fmt.Println(s)
    }

    // Gerichtete Channels — dokumentieren die Absicht
    var sendOnly chan&lt;- int = ch               // nur senden
    var recvOnly &lt;-chan int = ch               // nur empfangen
    _ = sendOnly; _ = recvOnly; _ = v

    // select — Multiplexing von Channels
    ticker := time.NewTicker(500 * time.Millisecond)
    timeout := time.After(2 * time.Second)
    defer ticker.Stop()

    for {
        select {
        case t := &lt;-ticker.C:
            fmt.Println("tick:", t)
        case &lt;-timeout:
            fmt.Println("timeout!")
            return
        }
    }
}

// ──────────────────────────────────────────────
// Context — Abbruch, Timeouts, Weitergabe von Werten
// ──────────────────────────────────────────────
func fetchWithContext(ctx context.Context, url string) ([]byte, error) {
    req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
    if err != nil { return nil, err }

    resp, err := http.DefaultClient.Do(req)
    if err != nil { return nil, fmt.Errorf("fetch %s: %w", url, err) }
    defer resp.Body.Close()
    return io.ReadAll(resp.Body)
}

func contextUsage() {
    // Timeout
    ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
    defer cancel()                             // IMMER defer cancel()!

    data, err := fetchWithContext(ctx, "https://api.example.com")
    _ = data; _ = err

    // Deadline
    deadline := time.Now().Add(10 * time.Second)
    ctx2, cancel2 := context.WithDeadline(context.Background(), deadline)
    defer cancel2()
    _ = ctx2

    // Abbruch
    ctx3, cancel3 := context.WithCancel(context.Background())
    go func() {
        time.Sleep(2 * time.Second)
        cancel3()                              // Abbruchsignal
    }()

    select {
    case &lt;-ctx3.Done():
        fmt.Println("cancelled:", ctx3.Err()) // context.Canceled
    }
}

// ──────────────────────────────────────────────
// Muster: Worker Pool
// ──────────────────────────────────────────────
func workerPool(ctx context.Context, jobs []int, numWorkers int) []int {
    jobCh    := make(chan int, len(jobs))
    resultCh := make(chan int, len(jobs))

    // Worker starten
    var wg sync.WaitGroup
    for range numWorkers {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for {
                select {
                case job, ok := &lt;-jobCh:
                    if !ok { return }
                    result := job * job        // aufwändige Arbeit
                    resultCh &lt;- result
                case &lt;-ctx.Done():
                    return
                }
            }
        }()
    }

    // Jobs senden
    for _, j := range jobs { jobCh &lt;- j }
    close(jobCh)

    // resultCh schließen, nachdem alle Worker fertig sind
    go func() {
        wg.Wait()
        close(resultCh)
    }()

    // Ergebnisse sammeln
    var results []int
    for r := range resultCh {
        results = append(results, r)
    }
    return results
}

// ──────────────────────────────────────────────
// Muster: Fan-out / Fan-in
// ──────────────────────────────────────────────
func fanOut[T, R any](
    ctx context.Context,
    items []T,
    workers int,
    process func(context.Context, T) (R, error),
) ([]R, []error) {
    type item struct{ val T }
    type result struct {
        val R
        err error
    }

    jobCh    := make(chan item, len(items))
    resultCh := make(chan result, len(items))

    var wg sync.WaitGroup
    for range workers {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for j := range jobCh {
                v, err := process(ctx, j.val)
                resultCh &lt;- result{v, err}
            }
        }()
    }

    for _, i := range items { jobCh &lt;- item{i} }
    close(jobCh)

    go func() { wg.Wait(); close(resultCh) }()

    var vals []R
    var errs []error
    for r := range resultCh {
        if r.err != nil { errs = append(errs, r.err) } else { vals = append(vals, r.val) }
    }
    return vals, errs
}

// ──────────────────────────────────────────────
// errgroup — Goroutines mit Fehlerbehandlung
// go get golang.org/x/sync
// ──────────────────────────────────────────────
import "golang.org/x/sync/errgroup"

func fetchMultiple(urls []string) ([][]byte, error) {
    g, ctx := errgroup.WithContext(context.Background())
    results := make([][]byte, len(urls))

    for i, url := range urls {
        i, url := i, url                      // capture!
        g.Go(func() error {
            data, err := fetchWithContext(ctx, url)
            if err != nil { return err }
            results[i] = data
            return nil
        })
    }

    if err := g.Wait(); err != nil {
        return nil, err
    }
    return results, nil
}
