// RWMutex — mehrere Leser, ein Schreiber
type SafeMap[K comparable, V any] struct {
    mu sync.RWMutex
    m  map[K]V
}

func NewSafeMap[K comparable, V any]() *SafeMap[K, V] {
    return &amp;SafeMap[K, V]{m: make(map[K]V)}
}

func (s *SafeMap[K, V]) Set(k K, v V) {
    s.mu.Lock()
    defer s.mu.Unlock()
    s.m[k] = v
}

func (s *SafeMap[K, V]) Get(k K) (V, bool) {
    s.mu.RLock()                              // nur Lesen — RLock
    defer s.mu.RUnlock()
    v, ok := s.m[k]
    return v, ok
}

func (s *SafeMap[K, V]) Delete(k K) {
    s.mu.Lock()
    defer s.mu.Unlock()
    delete(s.m, k)
}

// ──────────────────────────────────────────────
// sync/atomic — lock-free Operationen
// ──────────────────────────────────────────────
type AtomicCounter struct {
    count int64                               // MUSS 64-Bit-ausgerichtet sein!
}

func (c *AtomicCounter) Add(delta int64) int64 {
    return atomic.AddInt64(&amp;c.count, delta)
}
func (c *AtomicCounter) Load() int64 {
    return atomic.LoadInt64(&amp;c.count)
}
func (c *AtomicCounter) Store(val int64) {
    atomic.StoreInt64(&amp;c.count, val)
}
func (c *AtomicCounter) CompareAndSwap(old, new int64) bool {
    return atomic.CompareAndSwapInt64(&amp;c.count, old, new)
}
func (c *AtomicCounter) Swap(new int64) int64 {
    return atomic.SwapInt64(&amp;c.count, new)
}

// atomic.Value — beliebigen Wert atomar speichern (für Konfiguration)
type ConfigHolder struct {
    val atomic.Value                          // speichert *Config
}

func (h *ConfigHolder) Get() *Config {
    v := h.val.Load()
    if v == nil { return nil }
    return v.(*Config)
}

func (h *ConfigHolder) Set(cfg *Config) {
    h.val.Store(cfg)                          // atomarer Austausch der Konfiguration
}

