// ──────────────────────────────────────────────
type Singleton struct {
    data string
}

var (
    instance *Singleton
    once     sync.Once
)

func GetInstance() *Singleton {
    once.Do(func() {
        instance = &amp;Singleton{data: "initialized"}
    })
    return instance                            // thread-sicherer Singleton!
}

// ──────────────────────────────────────────────
// sync.Pool — Wiederverwendung von Objekten (GC-Druck reduzieren)
// ──────────────────────────────────────────────
var bufPool = sync.Pool{
    New: func() any {
        buf := make([]byte, 0, 4096)
        return &amp;buf
    },
}

func processRequest(data []byte) []byte {
    bufPtr := bufPool.Get().(*[]byte)
    defer func() {
        *bufPtr = (*bufPtr)[:0]               // Länge zurücksetzen (Capacity beibehalten)
        bufPool.Put(bufPtr)
    }()

    *bufPtr = append(*bufPtr, data...)
    result := process(*bufPtr)
    return result
}

// ──────────────────────────────────────────────
// sync.WaitGroup + errgroup-Muster
// ──────────────────────────────────────────────
func concurrent() {
    var wg sync.WaitGroup
    results := make([]int, 10)

    for i := range 10 {
        wg.Add(1)
        go func(idx int) {
            defer wg.Done()
            results[idx] = idx * idx          // sicher: jeder schreibt in seinen eigenen Index
        }(i)
    }
    wg.Wait()
    fmt.Println(results)
}

