    fmt.Println("GOMAXPROCS:", runtime.GOMAXPROCS(0))  // 0 = aktuellen Wert lesen
    fmt.Println("Goroutines:", runtime.NumGoroutine())

    // Go 1.25: automatisches container-aware GOMAXPROCS
    // muss in Containern nicht mehr manuell gesetzt werden!
    // (früher war uber-go/automaxprocs nötig)
}

// ──────────────────────────────────────────────
// Häufiger Fehler: goroutine leak
// ──────────────────────────────────────────────
// SCHLECHT — die Goroutine hängt ewig, wenn niemand von ch liest
func leaky() &lt;-chan int {
    ch := make(chan int)
    go func() {
        ch &lt;- expensiveOperation()             // blockiert, wenn niemand liest!
    }()
    return ch
}

// GUT — die Goroutine beendet sich über context
func notLeaky(ctx context.Context) &lt;-chan int {
    ch := make(chan int, 1)                   // buffered!
    go func() {
        result := expensiveOperation()
        select {
        case ch &lt;- result:
        case &lt;-ctx.Done():                    // beenden, wenn abgebrochen
        }
    }()
    return ch
}
