// Context-aware Logger — request_id zu jeder Zeile hinzufügen
// ──────────────────────────────────────────────
type ctxKey string
const loggerKey ctxKey = "logger"

func WithLogger(ctx context.Context, log *slog.Logger) context.Context {
    return context.WithValue(ctx, loggerKey, log)
}

func LoggerFromCtx(ctx context.Context) *slog.Logger {
    if log, ok := ctx.Value(loggerKey).(*slog.Logger); ok {
        return log
    }
    return slog.Default()
}

// Middleware — request_id zum Logger im Context hinzufügen
func requestLoggerMiddleware(log *slog.Logger, next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        requestID := r.Header.Get("X-Request-ID")
        if requestID == "" {
            requestID = generateID()
        }
        reqLog := log.With(
            slog.String("request_id", requestID),
            slog.String("method", r.Method),
            slog.String("path", r.URL.Path),
        )
        ctx := WithLogger(r.Context(), reqLog)
        reqLog.Info("request started")
        next.ServeHTTP(w, r.WithContext(ctx))
    })
}

// Im Handler — Logger aus dem Context holen
func (h *Handler) getUser(w http.ResponseWriter, r *http.Request) {
    log := LoggerFromCtx(r.Context())          // trägt automatisch request_id
    log.Info("getting user", "id", r.PathValue("id"))
    // ...
}

// ──────────────────────────────────────────────
// Eigener slog.Handler — z. B. für Versand an Sentry
// ──────────────────────────────────────────────
type MultiHandler struct {
    handlers []slog.Handler
}

func NewMultiHandler(handlers ...slog.Handler) *MultiHandler {
    return &amp;MultiHandler{handlers: handlers}
}

func (m *MultiHandler) Enabled(ctx context.Context, level slog.Level) bool {
    for _, h := range m.handlers {
        if h.Enabled(ctx, level) { return true }
    }
    return false
}

func (m *MultiHandler) Handle(ctx context.Context, r slog.Record) error {
    for _, h := range m.handlers {
        if h.Enabled(ctx, r.Level) {
            if err := h.Handle(ctx, r); err != nil { return err }
        }
    }
    return nil
}

func (m *MultiHandler) WithAttrs(attrs []slog.Attr) slog.Handler {
    handlers := make([]slog.Handler, len(m.handlers))
    for i, h := range m.handlers { handlers[i] = h.WithAttrs(attrs) }
    return NewMultiHandler(handlers...)
}

func (m *MultiHandler) WithGroup(name string) slog.Handler {
    handlers := make([]slog.Handler, len(m.handlers))
    for i, h := range m.handlers { handlers[i] = h.WithGroup(name) }
    return NewMultiHandler(handlers...)
}

