    KindRectangle
    KindTriangle
)

type Shape struct {
    Kind ShapeKind
    // Nur eines der Felder ist gesetzt (Sum Type über struct)
    Circle    *CircleData
    Rectangle *RectData
}

type CircleData    struct { Radius float64 }
type RectData      struct { Width, Height float64 }

func area(s Shape) float64 {
    switch s.Kind {
    case KindCircle:
        return math.Pi * s.Circle.Radius * s.Circle.Radius
    case KindRectangle:
        return s.Rectangle.Width * s.Rectangle.Height
    default:
        return 0
    }
}

