type Config struct {
    DBHost     string
    DBPort     int
    DBName     string
    DBPassword string
    JWTSecret  string
    Port       int
    Debug      bool
}

func LoadConfig() (*Config, error) {
    // .env-Datei laden (nur für Entwicklung!)
    if err := godotenv.Load(); err != nil {
        // .env ist in Produktion nicht erforderlich
        slog.Debug(".env not found, using environment variables")
    }

    cfg := &amp;Config{}

    cfg.DBHost = getEnvOrDefault("DB_HOST", "localhost")
    cfg.DBName = requireEnv("DB_NAME")        // panic wenn nicht gesetzt
    cfg.JWTSecret = requireEnv("JWT_SECRET")

    var err error
    cfg.DBPort, err = getEnvInt("DB_PORT", 5432)
    if err != nil { return nil, err }

    cfg.Port, err = getEnvInt("PORT", 8080)
    if err != nil { return nil, err }

    cfg.Debug = getEnvBool("DEBUG", false)

    return cfg, nil
}

func getEnvOrDefault(key, def string) string {
    if v := os.Getenv(key); v != "" { return v }
    return def
}

func requireEnv(key string) string {
    v := os.Getenv(key)
    if v == "" {
        panic(fmt.Sprintf("required environment variable %q is not set", key))
    }
    return v
}

func getEnvInt(key string, def int) (int, error) {
    s := os.Getenv(key)
    if s == "" { return def, nil }
    n, err := strconv.Atoi(s)
    if err != nil { return 0, fmt.Errorf("env %s must be int: %w", key, err) }
    return n, nil
}

func getEnvBool(key string, def bool) bool {
    s := os.Getenv(key)
    if s == "" { return def }
    b, _ := strconv.ParseBool(s)
    return b
}
