// Panic und recover (nur für kritische Fehler!)
// ──────────────────────────────────────────────
func safeDivide(a, b int) (result int, err error) {
    defer func() {
        if r := recover(); r != nil {
            err = fmt.Errorf("recovered from panic: %v", r)
        }
    }()
    return a / b, nil                          // panic bei b==0
}

