func fileBasics() error {
    // ─── Datei schreiben ─────────────────────
    // os.WriteFile — atomarer Schreibvorgang (über Temp-Datei auf den meisten FS)
    data := []byte("Hello, Go!\n")
    if err := os.WriteFile("output.txt", data, 0644); err != nil {
        return fmt.Errorf("write file: %w", err)
    }

    // Schreiben über os.Create + bufio.Writer (effizient für große Dateien)
    f, err := os.Create("large.txt")
    if err != nil { return err }
    defer f.Close()

    bw := bufio.NewWriterSize(f, 64*1024)      // 64-KB-Puffer
    for i := range 100_000 {
        fmt.Fprintf(bw, "line %d\n", i)
    }
    if err := bw.Flush(); err != nil { return err } // Puffer flushen!

    // ─── Datei lesen ─────────────────────────
    content, err := os.ReadFile("output.txt") // gesamte Datei in den Speicher
    if err != nil { return err }
    fmt.Println(string(content))

    // Byte-/zeilenweises Lesen (große Dateien)
    f2, err := os.Open("large.txt")
    if err != nil { return err }
    defer f2.Close()

    scanner := bufio.NewScanner(f2)
    scanner.Buffer(make([]byte, 1&lt;&lt;20), 1&lt;&lt;20) // 1-MB-Puffer für lange Zeilen
    lineCount := 0
    for scanner.Scan() {
        line := scanner.Text()
        _ = line
        lineCount++
    }
    if err := scanner.Err(); err != nil { return err }
    fmt.Println("lines:", lineCount)

    // ─── An das Dateiende anhängen ──────────
    f3, err := os.OpenFile("log.txt",
        os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
    if err != nil { return err }
    defer f3.Close()
    fmt.Fprintln(f3, time.Now().Format(time.RFC3339), "app started")

    // ─── Existenzprüfung / stat ─────────────
    info, err := os.Stat("output.txt")
    if err != nil {
        if errors.Is(err, os.ErrNotExist) {
            fmt.Println("file not found")
        }
        return err
    }
    fmt.Printf("size=%d mode=%s modtime=%s\n",
        info.Size(), info.Mode(), info.ModTime())

    // ─── Umbenennen und löschen ─────────────
    os.Rename("output.txt", "output_new.txt")
    os.Remove("output_new.txt")
    os.RemoveAll("temp_dir")               // rekursiv

    return nil
}

// ──────────────────────────────────────────────
// Arbeit mit Verzeichnissen
