func dirOperations() error {
    // Verzeichnisse erstellen
    os.MkdirAll("data/cache/tmp", 0755)    // wie mkdir -p

    // Verzeichnis auflisten
    entries, err := os.ReadDir(".")
    if err != nil { return err }
    for _, e := range entries {
        info, _ := e.Info()
        fmt.Printf("%-30s %8d %s\n", e.Name(), info.Size(), info.Mode())
    }

    // Rekursiver Walk — filepath.WalkDir (Go 1.16+, effizienter als Walk)
    err = filepath.WalkDir(".", func(path string, d fs.DirEntry, err error) error {
        if err != nil { return err }

        if d.IsDir() &amp;&amp; d.Name() == ".git" {
            return filepath.SkipDir  // Unterbaum überspringen
        }

        if !d.IsDir() &amp;&amp; strings.HasSuffix(path, ".go") {
            info, _ := d.Info()
            fmt.Printf("%s (%d bytes)\n", path, info.Size())
        }
        return nil
    })

    // Temp-Dateien — automatisch sicherer Name
    tmpFile, err := os.CreateTemp("", "app-*.tmp")  // * wird durch Zufallsstring ersetzt
    if err != nil { return err }
    defer os.Remove(tmpFile.Name())                  // beim Beenden entfernen
    defer tmpFile.Close()
    tmpFile.WriteString("temp data")

    // Temp-Verzeichnis
    tmpDir, err := os.MkdirTemp("", "app-*")
    if err != nil { return err }
    defer os.RemoveAll(tmpDir)

    _ = err
    return nil
}

// ──────────────────────────────────────────────
// Atomarer Dateischreibvorgang — über rename
// (Schutz vor Datenverlust bei Crash mitten im Schreiben)
// ──────────────────────────────────────────────
func writeFileAtomic(path string, data []byte, perm os.FileMode) error {
    dir := filepath.Dir(path)

    // Temp-Datei auf demselben FS erstellen (wichtig für atomic rename!)
    tmp, err := os.CreateTemp(dir, ".tmp-*")
    if err != nil { return fmt.Errorf("create temp: %w", err) }
    tmpName := tmp.Name()

    defer func() {
        tmp.Close()
        os.Remove(tmpName)                   // Cleanup, falls etwas schiefgeht
    }()

    if _, err := tmp.Write(data); err != nil {
        return fmt.Errorf("write temp: %w", err)
    }
    if err := tmp.Sync(); err != nil {       // fsync — auf Platte flushen!
        return fmt.Errorf("sync: %w", err)
    }
    tmp.Close()

    if err := os.Chmod(tmpName, perm); err != nil { return err }

    // Atomic rename: entweder alt oder neu — nie teilweise
    return os.Rename(tmpName, path)
}

