type Record struct {
    Name  string
    Email string
    Age   int
}

func writeCSV(path string, records []Record) error {
    f, err := os.Create(path)
    if err != nil { return err }
    defer f.Close()

    w := csv.NewWriter(f)
    defer w.Flush()                          // Flush ist ERFORDERLICH!

    // Header
    if err := w.Write([]string{"name", "email", "age"}); err != nil {
        return err
    }

    for _, r := range records {
        if err := w.Write([]string{
            r.Name, r.Email, strconv.Itoa(r.Age),
        }); err != nil { return err }
    }
    return w.Error()
}

func readCSV(path string) ([]Record, error) {
    f, err := os.Open(path)
    if err != nil { return nil, err }
    defer f.Close()

    r := csv.NewReader(f)
    r.TrimLeadingSpace = true
    r.Comment = '#'                          // Zeilen mit # ignorieren

    // Header überspringen
    if _, err := r.Read(); err != nil { return nil, err }

    var records []Record
    for {
        row, err := r.Read()
        if err == io.EOF { break }
        if err != nil { return nil, err }

        age, _ := strconv.Atoi(row[2])
        records = append(records, Record{
            Name:  row[0],
            Email: row[1],
            Age:   age,
        })
    }
    return records, nil
}

