func Map[T, R any](s []T, fn func(T) R) []R {
    result := make([]R, len(s))
    for i, v := range s { result[i] = fn(v) }
    return result
}

func Filter[T any](s []T, fn func(T) bool) []T {
    result := make([]T, 0, len(s)/2)
    for _, v := range s {
