        0f, 1f, 0f, 0f, brightness,
        0f, 0f, 1f, 0f, brightness,
        0f, 0f, 0f, 1f, 0f
    ))
    val result = Bitmap.createBitmap(width, height, Bitmap.Config.ARGB_8888)
    Canvas(result).drawBitmap(this, 0f, 0f,
        Paint().apply { colorFilter = ColorMatrixColorFilter(cm) })
    return result
