import "github.com/dlclark/regexp2"          // falls lookahead benötigt wird

func lookaheadExample() {
    // Zahlen, denen "$" VORAUSGEHT — positive lookbehind
    re := regexp2.MustCompile(`(?&lt;=\$)\d+`, 0)
    m, _ := re.FindStringMatch("apple: $5, banana: 3, cherry: $12")
    for ; m != nil; m, _ = re.FindNextMatch(m) {
        fmt.Println(m.String())               // "5", "12"
    }

    // Wörter vor ":" — positive lookahead
    re2 := regexp2.MustCompile(`\w+(?=:)`, 0)
    m2, _ := re2.FindStringMatch("name: Alice, age: 30")
    for ; m2 != nil; m2, _ = re2.FindNextMatch(m2) {
        fmt.Println(m2.String())              // "name", "age"
    }
}
