func TestDivide(t *testing.T) {
    tests := []struct {
        name    string
        a, b    float64
        want    float64
        wantErr bool
    }{
        {"positive",   10, 2,  5.0,  false},
        {"negative",   -9, 3, -3.0,  false},
        {"zero divisor", 5, 0,  0,   true},
        {"both zero",    0, 0,  0,   true},
        {"float result",  1, 3,  0.333, false},
    }

    for _, tc := range tests {
        t.Run(tc.name, func(t *testing.T) {       // t.Run — Subtest
            got, err := Divide(tc.a, tc.b)

            if tc.wantErr {
                require.Error(t, err)              // require: bei Fehler stoppen
                return
            }
            require.NoError(t, err)
            assert.InDelta(t, tc.want, got, 0.001) // Float mit Epsilon vergleichen
        })
    }
}

