func FuzzReverse(f *testing.F) {
    // Seed-Corpus — Anfangswerte
    f.Add("hello")
    f.Add("世界")
    f.Add("")
    f.Add("a b c")

    f.Fuzz(func(t *testing.T, s string) {
        reversed := Reverse(s)
        // Invarianten, die IMMER gelten müssen
        if len(s) != len(reversed) {
            t.Errorf("length changed: %d vs %d", len(s), len(reversed))
        }
        if Reverse(reversed) != s {           // doppeltes Reverse = Original
            t.Errorf("double reverse: got %q, want %q", Reverse(reversed), s)
        }
    })
}
